"""Generated set.mm assertion-site distinct-variable contracts.

The payload contains every non-empty active DV relation in Mono's phase1
target range.  Endpoints are stable set.mm variable names, never runtime
``SymbolId`` values.  Regenerate it whenever ``SOURCE_HASH`` changes.
"""

from __future__ import annotations

import base64
import json
import zlib
from collections.abc import Mapping
from typing import cast

SOURCE_HASH = "c95aaddc1ddd765352f8e8ffab89ab434f1de0cf50bd32651b85c9760bf5e25b"

_PAYLOAD = """"""

_raw = cast(dict[str, list[list[str]]], json.loads(zlib.decompress(base64.b64decode(_PAYLOAD))))
ACTIVE_DV_PAIRS: Mapping[str, tuple[tuple[str, str], ...]] = {
    label: tuple((left, right) for left, right in pairs) for label, pairs in _raw.items()
}

__all__ = ["ACTIVE_DV_PAIRS", "SOURCE_HASH"]
